import { useState, useEffect } from "react";
import { useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { login } from "../authReducer";
import bcrypt from "bcryptjs";

function Register() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [role, setRole] = useState("student");
  const [adminCount, setAdminCount] = useState(0);

  useEffect(() => {
    fetch("http://localhost:3001/users?role=admin")
      .then((res) => res.json())
      .then((data) => setAdminCount(data.length))
      .catch((error) => console.error("Error fetching admins:", error));
  }, []);

  async function handleRegister(e) {
    e.preventDefault();

    if (role === "admin" && adminCount >= 2) {
      alert("Only two admins are allowed!");
      return;
    }

    try {
      const hashedPassword = await bcrypt.hash(password, 10);
      const newUser = { email, password: hashedPassword, name, role };

      const response = await fetch("http://localhost:3001/users", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newUser),
      });

      if (response.ok) {
        const user = await response.json();
        dispatch(login(user));
        navigate("/dashboard");
      } else {
        alert("Registration failed");
      }
    } catch (error) {
      console.error("Fetch error:", error);
      alert("Failed to register due to a network error.");
    }
  }

  return (
    <div className="page-container">
      <div className="form-container">
        <form onSubmit={handleRegister}>
          <input
            type="text"
            placeholder="Name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
          />
          <input
            type="email"
            placeholder="Email address"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
          <select value={role} onChange={(e) => setRole(e.target.value)}>
            <option value="student">Student</option>
            <option value="teacher">Teacher</option>
            {adminCount < 2 && <option value="admin">Admin</option>}
          </select>
          {adminCount >= 2 && <p>Admin limit</p>}
          <button type="submit">Register</button>
        </form>
      </div>
    </div>
  );
}

export default Register;
